package uk.ac.ed.ltg.jdm.io;import java.util.ArrayList;import java.util.Iterator;import java.util.List;import org.apache.log4j.Logger;import uk.ac.ed.ltg.jdm.textdata.AbstractElement;import uk.ac.ed.ltg.jdm.textdata.Document;import uk.ac.ed.ltg.jdm.textdata.Paragraph;import uk.ac.ed.ltg.jdm.textdata.Zone;/** * Utility static methods for marking paragraphs as annotated or not-annotated * based on their content. This code was created to deal with some manually * annotated documents that were not correctly marked up to identify annotated * and non-annotated sections. It makes the assumption that a paragraph that * contains no entities is a non-annotated paragraph. *  */public class NotAnnotated {	/** The Constant logger. */	private static final Logger LOGGER = Logger.getLogger(NotAnnotated.class);	/** The Constant NOT_ANNOT_KEY. */	public static final String NOT_ANNOT_KEY = "not_annot";	/**	 * Creates the zone from annotated paragraphs.	 * 	 * @param document	 *            the document	 * 	 * @return the zone	 */	public static Zone createZoneFromAnnotatedParagraphs(final Document document) {		final Zone zone = new Zone(document);		final List<Paragraph> paragraphs = document.getTextSection()				.getParagraphs();		final Iterator<Paragraph> i = paragraphs.iterator();		if (!i.hasNext()) {			LOGGER.warn("Document contains no paragraphs "					+ "and therefore has no annotated zone");		} else {			while (i.hasNext()) {				final Paragraph p = i.next();				final String value = p.getAttribute(NOT_ANNOT_KEY);				if (value == null || !value.equals("true")) {					zone.addPart(p.getRange());				}			}		}		return zone;	}	/**	 * Filter elements in zone. * @param elementList the element list * @param	 * zone the zone * @return the list	 * 	 * @param elementList	 *            the element list	 * @param zone	 *            the zone	 * 	 * @return the list	 */	public static <T extends AbstractElement> List<T> filterElementsInZone(			final List<T> elementList, final Zone zone) {		final List<T> newList = new ArrayList<T>();		final Iterator<T> i = elementList.iterator();		while (i.hasNext()) {			final T e = i.next();			if (zone.contains(e.getRange())) {				newList.add(e);			}		}		return newList;	}}